// src/Navbar.js

import React, { useState, useEffect, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from './ThemeContext';
import { Sun, Moon, QrCode, Menu, X } from 'lucide-react';

// ── Static configs ────────────────────────────────────────────────────────────
const navEnter    = { initial: { y: -64, opacity: 0 }, animate: { y: 0, opacity: 1 }, transition: { duration: 0.35, ease: [0.25, 0.46, 0.45, 0.94] } };
const menuAnim    = { initial: { opacity: 0, height: 0 }, animate: { opacity: 1, height: 'auto' }, exit: { opacity: 0, height: 0 }, transition: { duration: 0.2 } };
const iconEnter   = { initial: { rotate: -90, opacity: 0 }, animate: { rotate: 0, opacity: 1 }, exit: { rotate: 90, opacity: 0 }, transition: { duration: 0.12 } };
const iconExit    = { initial: { rotate: 90, opacity: 0 },  animate: { rotate: 0, opacity: 1 }, exit: { rotate: -90, opacity: 0 }, transition: { duration: 0.12 } };
const indicatorT  = { type: 'spring', stiffness: 400, damping: 30 };

const NAV_TABS = [
  { id: 'main',      label: 'Generate & Scan', emoji: '⬡' },
  { id: 'utilities', label: 'Utilities',        emoji: '⚡' },
  { id: 'history',   label: 'History',          emoji: '📋' },
  { id: 'contact',   label: 'Contact',          emoji: '✉️' },
];

// ── Tab button ────────────────────────────────────────────────────────────────
const TabButton = memo(({ id, label, emoji, isActive, onClick }) => (
  <button
    type="button"
    onClick={() => onClick(id)}
    className="relative px-4 py-1.5 rounded-lg text-sm font-semibold transition-colors duration-200 z-10"
  >
    {isActive && (
      <motion.div
        layoutId="nav-indicator"
        className="absolute inset-0 bg-white dark:bg-[#0f0f1a] rounded-lg shadow-sm"
        transition={indicatorT}
      />
    )}
    <span className={"relative z-10 flex items-center gap-1.5 " + (isActive ? "text-purple-600 dark:text-purple-400" : "text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300")}>
      <span>{emoji}</span> {label}
    </span>
  </button>
));
TabButton.displayName = 'TabButton';

// ── Mobile menu item ──────────────────────────────────────────────────────────
const MobileMenuItem = memo(({ id, label, emoji, isActive, onClick, delay }) => (
  <motion.button
    type="button"
    initial={{ opacity: 0, x: -12 }}
    animate={{ opacity: 1, x: 0   }}
    transition={{ delay }}
    onClick={() => onClick(id)}
    className={"w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-colors duration-200 " +
      (isActive
        ? "bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 border border-purple-200 dark:border-purple-500/20"
        : "text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-[#1a1a2e]")}
  >
    <span className="text-lg">{emoji}</span>
    <span>{label}</span>
    {isActive && (
      <span className="ml-auto w-2 h-2 rounded-full bg-purple-500" />
    )}
  </motion.button>
));
MobileMenuItem.displayName = 'MobileMenuItem';

// ── Main Navbar ───────────────────────────────────────────────────────────────
const Navbar = memo(({ activeTab, onTabChange, onLogoClick, onStart, isLanding = false }) => {
  const { isDark, toggleTheme } = useTheme();
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleTabClick = useCallback((tabId) => {
    onTabChange(tabId);
    setMenuOpen(false);
  }, [onTabChange]);

  const handleLogoClick = useCallback(() => {
    if (onLogoClick) onLogoClick();
    setMenuOpen(false);
  }, [onLogoClick]);

  const toggleMenu = useCallback(() => setMenuOpen((p) => !p), []);

  return (
    <>
      <motion.nav
        {...navEnter}
        className={
          "fixed top-0 left-0 right-0 z-50 transition-colors duration-200 " +
          (scrolled
            ? "bg-white/80 dark:bg-[#0f0f1a]/90 backdrop-blur-xl border-b border-gray-100 dark:border-purple-500/10 shadow-sm"
            : "bg-transparent")
        }
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">

            {/* Logo */}
            <button
              onClick={handleLogoClick}
              className="flex items-center gap-2 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-500 rounded-lg px-1"
            >
              <QrCode size={22} className="text-purple-600 dark:text-purple-400" />
              <span className="text-lg font-extrabold tracking-tight text-gray-900 dark:text-white">
                Qronetic
              </span>
              <span className="hidden sm:inline-block text-xs px-2 py-0.5 rounded-full bg-purple-100 dark:bg-purple-900/30 text-purple-600 dark:text-purple-400 font-semibold">
                FREE
              </span>
            </button>

            {/* Desktop tabs */}
            {!isLanding && (
              <div className="hidden md:flex items-center gap-1 bg-gray-100/80 dark:bg-[#1a1a2e]/80 backdrop-blur-sm p-1 rounded-xl border border-gray-200 dark:border-purple-500/10">
                <TabButton id="main"      label="Generate & Scan" emoji="⬡"  isActive={activeTab === 'main'}      onClick={handleTabClick} />
                <TabButton id="utilities" label="Utilities"        emoji="⚡" isActive={activeTab === 'utilities'} onClick={handleTabClick} />
                <TabButton id="history"   label="History"          emoji="📋" isActive={activeTab === 'history'}   onClick={handleTabClick} />
                <TabButton id="contact"   label="Contact"          emoji="✉️" isActive={activeTab === 'contact'}   onClick={handleTabClick} />
              </div>
            )}

            {/* Right controls */}
            <div className="flex items-center gap-2">

              {/* Get Started — landing only */}
              {isLanding && (
                <button
                  onClick={onStart}
                  className="px-4 py-1.5 rounded-full bg-purple-600 hover:bg-purple-700 text-white text-sm font-semibold transition-colors duration-200"
                >
                  Get Started →
                </button>
              )}

              {/* Theme toggle */}
              <button
                onClick={toggleTheme}
                aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
                title={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
                className="p-2 rounded-xl bg-white/20 dark:bg-[#1a1a2e]/60 backdrop-blur-sm border border-gray-200/50 dark:border-purple-500/20 text-gray-700 dark:text-gray-300 hover:border-purple-400/40 transition-colors duration-200"
              >
                {isDark
                  ? <Sun  size={18} className="text-yellow-400" />
                  : <Moon size={18} className="text-indigo-500" />
                }
              </button>

              {/* Mobile hamburger */}
              {!isLanding && (
                <button
                  onClick={toggleMenu}
                  aria-label="Toggle navigation menu"
                  aria-expanded={menuOpen}
                  className="md:hidden p-2 rounded-xl bg-gray-100 dark:bg-[#1a1a2e] border border-gray-200 dark:border-purple-500/20 text-gray-600 dark:text-gray-300 transition-colors duration-200"
                >
                  <AnimatePresence mode="wait">
                    {menuOpen
                      ? <motion.div key="x"    {...iconEnter}><X    size={18} /></motion.div>
                      : <motion.div key="menu" {...iconExit} ><Menu size={18} /></motion.div>
                    }
                  </AnimatePresence>
                </button>
              )}

            </div>
          </div>
        </div>

        {/* Mobile dropdown */}
        {!isLanding && (
          <AnimatePresence>
            {menuOpen && (
              <motion.div
                {...menuAnim}
                className="md:hidden overflow-hidden border-t border-gray-100 dark:border-purple-500/10 bg-white/95 dark:bg-[#0f0f1a]/95 backdrop-blur-xl"
              >
                <div className="px-4 py-3 space-y-1">
                  <MobileMenuItem id="main"      label="Generate & Scan" emoji="⬡"  isActive={activeTab === 'main'}      onClick={handleTabClick} delay={0}    />
                  <MobileMenuItem id="utilities" label="Utilities"        emoji="⚡" isActive={activeTab === 'utilities'} onClick={handleTabClick} delay={0.05} />
                  <MobileMenuItem id="history"   label="History"          emoji="📋" isActive={activeTab === 'history'}   onClick={handleTabClick} delay={0.1}  />
                  <MobileMenuItem id="contact"   label="Contact"          emoji="✉️" isActive={activeTab === 'contact'}   onClick={handleTabClick} delay={0.15} />
                  <div className="pt-2 mt-2 border-t border-gray-100 dark:border-purple-500/10">
                    <p className="text-xs text-gray-400 dark:text-gray-600 text-center py-1">
                      Free · Private · No sign-up
                    </p>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        )}
      </motion.nav>

      {!isLanding && <div className="h-16" />}
    </>
  );
});

Navbar.displayName = 'Navbar';
export default Navbar;