// src/AnimatedButton.js

import React, { memo } from 'react';
import './AnimatedButton.css';

const AnimatedButton = memo(({ onClick, label = "Start Generating", icon = "✦" }) => {
  return (
    <button
      className="animated-btn"
      onClick={onClick}
      aria-label={label}
      type="button"
    >
      <div className="animated-btn__wrap">
        <p className="animated-btn__text">
          {label}
          <span className="animated-btn__icon-default">{icon}</span>
          <span className="animated-btn__icon-hover">✦</span>
        </p>
      </div>
    </button>
  );
});

AnimatedButton.displayName = 'AnimatedButton';

export default AnimatedButton;