// src/App.js

import React, { Suspense, lazy, useState, useEffect, useCallback, memo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ThemeProvider } from './ThemeContext';
import LandingSection from './LandingSection';
import Contact from './Contact';
import StaticBackToTop from './StaticBackToTop';
import Footer from './Footer';
import Navbar from './Navbar';
import { QrCode } from 'lucide-react';

// ── Lazy imports with prefetch hints ─────────────────────────────────────────
const GeneratorSection = lazy(() => import('./GeneratorSection'));
const ScannerSection   = lazy(() => import('./ScannerSection'));
const QrUtilities      = lazy(() => import('./QrUtilities'));

// Prefetch chunks after initial load so tab switching feels instant
const prefetchAll = () => {
  import('./GeneratorSection');
  import('./ScannerSection');
  import('./QrUtilities');
};

// ── Transition configs defined outside component to avoid re-creation ────────
const landingExitTransition = {
  opacity: 0,
  y: -30,
  filter: 'blur(8px)',
  transition: { duration: 0.4, ease: [0.25, 0.46, 0.45, 0.94] },
};

const appEnterTransition = {
  initial:    { opacity: 0, y: 16 },
  animate:    { opacity: 1, y: 0  },
  transition: { duration: 0.35, ease: [0.25, 0.46, 0.45, 0.94] },
};

const pageTransitionProps = {
  initial:    { opacity: 0, y: 12 },
  animate:    { opacity: 1, y: 0  },
  exit:       { opacity: 0, y: -12 },
  transition: { duration: 0.25, ease: [0.25, 0.46, 0.45, 0.94] },
};

// ── Loading fallback ──────────────────────────────────────────────────────────
const LoadingFallback = memo(() => (
  <div
    role="status"
    aria-live="polite"
    className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-[#0f0f1a]"
  >
    <div className="text-center space-y-5">
      <div className="relative w-20 h-20 mx-auto">
        <div className="absolute inset-0 rounded-full border-4 border-purple-500/20 border-t-purple-500 animate-spin" />
        <div className="absolute inset-0 flex items-center justify-center">
          <QrCode size={28} className="text-purple-400 animate-pulse" />
        </div>
      </div>
      <div className="space-y-1">
        <p className="text-gray-700 dark:text-gray-200 font-semibold text-lg">
          Loading Qronetic
        </p>
        <p className="text-gray-400 dark:text-gray-500 text-sm">
          Preparing your QR experience...
        </p>
      </div>
    </div>
  </div>
));
LoadingFallback.displayName = 'LoadingFallback';

// ── Skip link ─────────────────────────────────────────────────────────────────
const skipLinkClass = "sr-only focus:not-sr-only focus:fixed focus:top-4 focus:left-4 focus:z-50 focus:px-4 focus:py-2 focus:bg-purple-600 focus:text-white focus:rounded-lg focus:text-sm focus:font-medium";

// ── Page transition wrapper — no blur filter (expensive on mobile) ────────────
const PageTransition = memo(({ children, tabKey }) => (
  <AnimatePresence mode="wait">
    <motion.div
      key={tabKey}
      initial={pageTransitionProps.initial}
      animate={pageTransitionProps.animate}
      exit={pageTransitionProps.exit}
      transition={pageTransitionProps.transition}
    >
      {children}
    </motion.div>
  </AnimatePresence>
));
PageTransition.displayName = 'PageTransition';

// ── App content ───────────────────────────────────────────────────────────────
const AppContent = () => {
  const [activeTab, setActiveTab] = useState('main');
  const [view,      setView]      = useState('landing');

  useEffect(() => {
    const seen = sessionStorage.getItem('qronetic_seen');
    if (seen) setView('app');
  }, []);

  // Prefetch all chunks 2 seconds after mount
  useEffect(() => {
    const timer = setTimeout(prefetchAll, 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleStart = useCallback(() => {
    sessionStorage.setItem('qronetic_seen', '1');
    setView('app');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleGoToLanding = useCallback(() => {
    sessionStorage.removeItem('qronetic_seen');
    setView('landing');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleTabChange = useCallback((tab) => {
    setActiveTab(tab);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  return (
    <div className="bg-white dark:bg-[#0f0f1a] transition-colors duration-500">
      <a href="#main-content" className={skipLinkClass}>
        Skip to main content
      </a>

      <AnimatePresence mode="wait">

        {/* ── Landing view ── */}
        {view === 'landing' && (
          <motion.div
            key="landing"
            initial={{ opacity: 1 }}
            exit={landingExitTransition}
          >
            <Navbar
              activeTab={activeTab}
              onTabChange={handleTabChange}
              onLogoClick={handleGoToLanding}
              onStart={handleStart}
              isLanding={true}
            />
            <LandingSection onStart={handleStart} />
          </motion.div>
        )}

        {/* ── App view ── */}
        {view === 'app' && (
          <motion.div
            key="app"
            initial={appEnterTransition.initial}
            animate={appEnterTransition.animate}
            transition={appEnterTransition.transition}
          >
            <Navbar
              activeTab={activeTab}
              onTabChange={handleTabChange}
              onLogoClick={handleGoToLanding}
              onStart={handleStart}
              isLanding={false}
            />

            <main id="main-content" className="min-h-screen">
              <Suspense fallback={<LoadingFallback />}>

                {activeTab === 'main' && (
                  <PageTransition tabKey="main">
                    <GeneratorSection />
                    <ScannerSection />
                  </PageTransition>
                )}

                {activeTab === 'utilities' && (
                  <PageTransition tabKey="utilities">
                    <QrUtilities />
                  </PageTransition>
                )}

                {activeTab === 'history' && (
                  <PageTransition tabKey="history">
                    <GeneratorSection historyOnly />
                  </PageTransition>
                )}

                {activeTab === 'contact' && (
                  <PageTransition tabKey="contact">
                    <Contact />
                  </PageTransition>
                )}

              </Suspense>
            </main>

            <StaticBackToTop />
            <Footer />
          </motion.div>
        )}

      </AnimatePresence>
    </div>
  );
};

const App = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;